import { zodResolver } from '@hookform/resolvers/zod';
import { useMutation } from '@tanstack/react-query';
import { useForm } from 'react-hook-form';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { Button } from '@/shared/components/ui/button';
import { Input } from '@/shared/components/ui/input';
import { useAuthStore } from '@/store/useAuthStore';
import { login } from './authApi';
import { loginSchema } from './login.schema';

export const LoginPage = () => {
    const navigate = useNavigate();
    const [searchParams] = useSearchParams();
    const setUser = useAuthStore((state) => state.setUser);
    const returnUrl = searchParams.get('returnUrl') || '/home';
    const {
        register,
        handleSubmit,
        formState: { errors },
    } = useForm({
        resolver: zodResolver(loginSchema),
        defaultValues: {
            username: '',
            password: '',
        },
    });

    const mutation = useMutation({
        mutationFn: login,
        onSuccess: (data) => {
            setUser(data.user);
            navigate(returnUrl, { replace: true });
        },
    });

    return (
        <section className='w-full max-w-sm rounded-2xl border border-slate-200 bg-white p-8 shadow-xl shadow-slate-200/60 dark:border-slate-800 dark:bg-slate-950 dark:shadow-none'>
            <header className='mb-6 space-y-2'>
                <div className='mb-4 flex h-10 w-10 items-center justify-center rounded-xl bg-gradient-to-br from-blue-600 to-blue-400 text-base font-bold text-white shadow-sm'>
                    T
                </div>
                <h1 className='text-2xl font-semibold text-slate-900 dark:text-slate-100'>TrmWordDict</h1>
                <p className='text-sm text-slate-500 dark:text-slate-400'>행정 용어 사전 시스템</p>
            </header>
            <form className='space-y-4' onSubmit={handleSubmit((values) => mutation.mutate(values))}>
                <div className='space-y-2'>
                    <label className='text-sm font-medium text-slate-700 dark:text-slate-300' htmlFor='username'>
                        아이디
                    </label>
                    <Input id='username' autoComplete='username' {...register('username')} />
                    {errors.username ? (
                        <p className='text-sm text-rose-600 dark:text-rose-400'>{errors.username.message}</p>
                    ) : null}
                </div>
                <div className='space-y-2'>
                    <label className='text-sm font-medium text-slate-700 dark:text-slate-300' htmlFor='password'>
                        비밀번호
                    </label>
                    <Input id='password' type='password' autoComplete='current-password' {...register('password')} />
                    {errors.password ? (
                        <p className='text-sm text-rose-600 dark:text-rose-400'>{errors.password.message}</p>
                    ) : null}
                </div>
                {mutation.isError ? (
                    <p className='text-sm text-rose-600 dark:text-rose-400'>로그인에 실패했습니다.</p>
                ) : null}
                <Button className='w-full' type='submit' disabled={mutation.isPending}>
                    로그인
                </Button>
            </form>
        </section>
    );
};

